import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
function Registration() {
    const navigate = useNavigate()
    let [users, setUsers] = useState([])
  let [nameinput, changenameinput] = useState("")
  let [passwordinput, changepasswordinput] = useState("")
  let [cityinput, changecityinput] = useState("")
  function sendtologin() {
    navigate("/login")
  }
  function getinputn(e) {
    changenameinput(e.target.value)
  }
  function getinputp(e) {
    changepasswordinput(e.target.value)
  }
  function getinputc(e) {
    changecityinput(e.target.value)
  }
  async function func1() {  
    await fetch("http://localhost:5000/registration", {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        credentials: "include",
        body: JSON.stringify({nameforreg: nameinput, passwordforreg: passwordinput, cityforreg: cityinput})
      }
    )
    let res2 = await fetch("http://localhost:5000/apisessionregistered", {
      method: "GET",
      credentials: "include"
    })
    let usercreds = await res2.json()
    console.log(usercreds)
    if(usercreds.loggedIn == true) {
      navigate("/weather")
    }
  }
  return<>
    <div>
      <p>Create an acccount</p>
      <p>Username</p>
      <input value={nameinput} onChange={(e) => getinputn(e)}/>
      <p>Password</p>
      <input value={passwordinput} onChange={(e) => getinputp(e)}/>
      <p>City</p>
      <input value={cityinput} onChange={(e) => getinputc(e)}/>
      <button onClick={() => func1()}>Login</button>
      <a onClick={() => sendtologin()}>Already registered?</a>
    </div>
  </>
}
export default Registration
